    private boolean validateImageContent(Uri imageUri, String expectedMimeType) {
        ContentResolver resolver = getContentResolver();

        // Verify the actual MIME type matches what was declared
        String actualMimeType = resolver.getType(imageUri);
        if (actualMimeType != null && !actualMimeType.startsWith("image/")) {
            Log.w(TAG, "Actual MIME type is not an image: " + actualMimeType);
            return false;
        }

        // Check image dimensions without fully loading
        try {
            InputStream inputStream = resolver.openInputStream(imageUri);
            if (inputStream == null) {
                Log.w(TAG, "Cannot open input stream for URI");
                return false;
            }

            BitmapFactory.Options options = new BitmapFactory.Options();
            options.inJustDecodeBounds = true;
            BitmapFactory.decodeStream(inputStream, null, options);
            inputStream.close();

            if (options.outWidth <= 0 || options.outHeight <= 0) {
                Log.w(TAG, "Invalid image dimensions");
                return false;
            }

            if (options.outWidth > MAX_IMAGE_DIMENSION || options.outHeight > MAX_IMAGE_DIMENSION) {
                Log.w(TAG, "Image dimensions exceed maximum: " +
                        options.outWidth + "x" + options.outHeight);
                // We'll still allow it but will downsample when loading
            }

            return true;

        } catch (FileNotFoundException e) {
            Log.w(TAG, "Image file not found", e);
            return false;
        } catch (Exception e) {
            Log.w(TAG, "Error validating image content", e);
            return false;
        }
    }

    /**
     * Loads an image safely with appropriate downsampling to prevent OOM.
     */
    private Bitmap loadImageSafely(Uri imageUri) {
        ContentResolver resolver = getContentResolver();

        try {
            // First pass: get dimensions
            InputStream inputStream = resolver.openInputStream(imageUri);
            if (inputStream == null) return null;

            BitmapFactory.Options options = new BitmapFactory.Options();
            options.inJustDecodeBounds = true;
            BitmapFactory.decodeStream(inputStream, null, options);
            inputStream.close();

            // Calculate sample size for downsampling
            int targetWidth = 1024;
            int targetHeight = 1024;
            options.inSampleSize = calculateInSampleSize(options, targetWidth, targetHeight);

            // Second pass: decode with downsampling
            options.inJustDecodeBounds = false;
            options.inPreferredConfig = Bitmap.Config.ARGB_8888;

            inputStream = resolver.openInputStream(imageUri);
            if (inputStream == null) return null;

            Bitmap bitmap = BitmapFactory.decodeStream(inputStream, null, options);
            inputStream.close();

            return bitmap;

        } catch (FileNotFoundException e) {
            Log.e(TAG, "Image file not found", e);
            return null;
        } catch (Exception e) {
            Log.e(TAG, "Error loading image", e);
            return null;
        } catch (OutOfMemoryError e) {
            Log.e(TAG, "Out of memory loading image", e);
            return null;
        }
    }

    /**
     * Calculates the appropriate sample size for bitmap downsampling.
     */
    private int calculateInSampleSize(BitmapFactory.Options options,
                                       int reqWidth, int reqHeight) {
        int height = options.outHeight;
        int width = options.outWidth;
        int inSampleSize = 1;

        if (height > reqHeight || width > reqWidth) {
            int halfHeight = height / 2;
            int halfWidth = width / 2;

            while ((halfHeight / inSampleSize) >= reqHeight
                    && (halfWidth / inSampleSize) >= reqWidth) {
                inSampleSize *= 2;
            }
        }

        return inSampleSize;
    }

    /**
     * Checks if the MIME type is an allowed image type.
     */
    private boolean isAllowedImageMimeType(String mimeType) {
        if (mimeType == null) return false;

        // Check exact match first
        if (ALLOWED_IMAGE_MIME_TYPES.contains(mimeType.toLowerCase())) {
            return true;
        }

        // Check if it's a generic image/* type
        if (mimeType.toLowerCase().startsWith("image/")) {
            // Allow generic image types but log for monitoring
            String subType = mimeType.substring(6).toLowerCase();
            // Block potentially dangerous subtypes
            if (subType.contains("svg") || subType.contains("xml")) {
                Log.w(TAG, "Blocked potentially dangerous image type: " + mimeType);
                return false;
            }
            return true;
        }

        return false;
    }

    /**
     * Sanitizes text input to remove potentially harmful content.
     */
    private String sanitizeText(String input) {
        if (input == null) return "";

        // Remove null bytes
        input = input.replace("\0", "");

        // Trim whitespace
        input = input.trim();

        // Remove control characters except newlines and tabs
        StringBuilder sanitized = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            if (c == '\n' || c == '\r' || c == '\t' || !Character.isISOControl(c)) {
                sanitized.append(c);
            }
        }

        return sanitized.toString();
    }

    /**
     * Checks if text contains a URL.
     */
    private boolean containsUrl(String text) {
        if (text == null) return false;
        return text.contains("http://") || text.contains("https://") ||
                text.contains("ftp://") || text.contains("www.");
    }

    /**
     * Performs basic safety checks on URLs in shared text.
     */
    private boolean isUrlSafe(String text) {
        if (text == null) return false;

        // Block javascript: and data: URIs that might be embedded
        String lowerText = text.toLowerCase();
        if (lowerText.contains("javascript:") || lowerText.contains("data:text/html")) {
            Log.w(TAG, "Blocked potentially dangerous URI scheme in text");
            return false;
        }

        // Block file:// URIs in shared text
        if (lowerText.contains("file://")) {
            Log.w(TAG, "Blocked file:// URI in shared text");
            return false;
        }

        return true;
    }

